import React, { useState } from 'react';
import { Outlet, NavLink } from 'react-router-dom';
import AlertsBell from './AlertsBell';

const navLinks = [
  { to: "/",            label: "Overview" },
  { to: "/trucks",      label: "Truck Management" },
  { to: "/scrap",       label: "Scrap Management" },
  { to: "/diesel",      label: "Diesel Inventory" },
  { to: "/dashboard",   label: "Dashboard" },
  { to: "/drivers",     label: "Driver Advances" },
  { to: "/maintenance", label: "Maintenance Log" },
  { to: "/customers",   label: "Customer Ledger" },
];

export default function Layout() {
  const [collapsed, setCollapsed] = useState(false);
  const [tripSaveCount, setTripSaveCount] = useState(0);

  return (
    <div style={s.shell}>
      <aside style={{ ...s.sidebar, width: collapsed ? 60 : 224 }}>

        {/* Logo */}
        <div style={s.logoBlock}>
          <div style={s.logoMark}>M</div>
          {!collapsed && (
            <div>
              <div style={s.logoName}>Maruti Group</div>
              <div style={s.logoSub}>Transport Division</div>
            </div>
          )}
        </div>

        <div style={s.divider} />

        {/* Nav */}
        <nav style={s.nav}>
          {navLinks.map((l) => (
            <NavLink
              key={l.to}
              to={l.to}
              end={l.to === "/"}
              style={({ isActive }) => ({
                ...s.link,
                ...(isActive ? s.linkActive : {}),
              })}
            >
              {!collapsed && <span>{l.label}</span>}
              {collapsed && <span style={s.collapsedDot} />}
            </NavLink>
          ))}
        </nav>

        <button style={s.collapseBtn} onClick={() => setCollapsed(c => !c)}>
          {collapsed ? '›' : '‹'}
        </button>
      </aside>

      <div style={s.body}>
        <header style={s.topbar}>
          <div style={s.topbarTitle}>
            Maruti Group · Transport Management System
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
            <AlertsBell refreshTrigger={tripSaveCount} />
            <div style={s.topbarDate}>
              {new Date().toLocaleDateString('en-IN', {
                weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
              })}
            </div>
          </div>
        </header>
        <main style={s.main}>
          <Outlet context={{ onTripSaved: () => setTripSaveCount(c => c + 1) }} />
        </main>
      </div>
    </div>
  );
}

const DARK       = '#0f2318';
const DARK2      = '#162e20';
const AMBER      = '#d97706';
const LINK_DEF   = 'rgba(255,255,255,0.6)';
const LINK_ACT   = '#ffffff';
const LINK_ACT_BG = 'rgba(255,255,255,0.1)';

const s = {
  shell: {
    display: 'flex',
    minHeight: '100vh',
    fontFamily: "'Plus Jakarta Sans', sans-serif",
  },
  sidebar: {
    background: DARK,
    display: 'flex',
    flexDirection: 'column',
    flexShrink: 0,
    transition: 'width 0.22s ease',
    overflow: 'hidden',
    position: 'sticky',
    top: 0,
    height: '100vh',
    borderRight: `1px solid rgba(255,255,255,0.05)`,
  },
  logoBlock: {
    display: 'flex',
    alignItems: 'center',
    gap: 11,
    padding: '22px 14px 18px',
    flexShrink: 0,
  },
  logoMark: {
    width: 34,
    height: 34,
    borderRadius: 8,
    background: AMBER,
    color: '#fff',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontWeight: 900,
    fontSize: 17,
    flexShrink: 0,
    letterSpacing: '-0.5px',
  },
  logoName: {
    fontSize: 13,
    fontWeight: 700,
    color: '#fff',
    whiteSpace: 'nowrap',
    letterSpacing: '0.01em',
  },
  logoSub: {
    fontSize: 10,
    color: 'rgba(255,255,255,0.4)',
    marginTop: 2,
    whiteSpace: 'nowrap',
    letterSpacing: '0.03em',
  },
  divider: {
    height: 1,
    background: 'rgba(255,255,255,0.07)',
    margin: '0 14px 10px',
  },
  nav: {
    display: 'flex',
    flexDirection: 'column',
    gap: 2,
    padding: '0 10px',
    flex: 1,
  },
  link: {
    display: 'flex',
    alignItems: 'center',
    padding: '9px 12px',
    borderRadius: 7,
    color: LINK_DEF,
    textDecoration: 'none',
    fontSize: 13,
    fontWeight: 500,
    whiteSpace: 'nowrap',
    transition: 'background 0.15s, color 0.15s',
    borderLeft: '2px solid transparent',
  },
  linkActive: {
    background: LINK_ACT_BG,
    color: LINK_ACT,
    fontWeight: 650,
    borderLeft: `2px solid ${AMBER}`,
    borderRadius: '0 7px 7px 0',
  },
  collapsedDot: {
    width: 5,
    height: 5,
    borderRadius: '50%',
    background: 'rgba(255,255,255,0.3)',
  },
  collapseBtn: {
    margin: '10px 10px 22px',
    padding: '8px',
    background: 'rgba(255,255,255,0.06)',
    border: '1px solid rgba(255,255,255,0.08)',
    borderRadius: 7,
    cursor: 'pointer',
    fontSize: 16,
    color: 'rgba(255,255,255,0.4)',
    textAlign: 'center',
    transition: 'background 0.15s',
  },
  body: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    background: '#f7f5f1',
    minWidth: 0,
  },
  topbar: {
    background: '#f7f5f1',
    borderBottom: '1px solid #e8e3db',
    padding: '0 32px',
    height: 52,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    flexShrink: 0,
  },
  topbarTitle: {
    fontSize: 13,
    fontWeight: 600,
    color: '#4a4033',
    letterSpacing: '0.01em',
  },
  topbarDate: {
    fontSize: 12,
    color: '#a89880',
    fontWeight: 500,
  },
  main: { padding: '32px', flex: 1 },
};
